package com.kylin.fast.openai.result.dto;

import com.google.gson.annotations.SerializedName;
import com.kylin.fast.openai.request.dto.Message;
import lombok.*;
import lombok.experimental.FieldDefaults;

/**
 * A completion generated by GPT-3
 * <p>
 * https://beta.openai.com/docs/api-reference/completions/create
 */
@FieldDefaults(level = AccessLevel.PRIVATE)
@Builder
@NoArgsConstructor
@AllArgsConstructor
@Data
@ToString
public class ChatChoice {
    /**
     * The generated text. Will include the prompt
     */
    Message message;

    /**
     * This index of this completion in the returned list.
     */
    Integer index;

    /**
     * The log probabilities of the chosen tokens and the top
     */
    LogProbResult logprobs;

    /**
     * The reason why GPT-3 stopped generating, for example "length".
     */
    @SerializedName("finish_reason")
    String finish_reason;
}
